#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A[11];
        for(int i=1;i<=10;i++) scanf("%lld", &A[i]);
        long long K; scanf("%lld", &K);
        for(int i=10;i>=1;i--){
            if(K>=A[i]){ K-=A[i]; A[i]=0; }
            else break;
        }
        int ans=1;
        for(int i=10;i>=1;i--){ if(A[i]>0){ ans=i; break; } }
        printf("%d\n", ans);
    }
    return 0;
}

