#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = [0] + [int(next(it)) for _ in range(10)]  # 1‑based
        K = int(next(it))
        for i in range(10, 0, -1):
            if K >= A[i]:
                K -= A[i]
                A[i] = 0
            else:
                break
        ans = 1
        for i in range(10, 0, -1):
            if A[i] > 0:
                ans = i
                break
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

